   261→#ifdef NCCL_HAS_COMM_SHRINK
   262→std::shared_ptr<NCCLComm> NCCLComm::shrink(
   263→    NCCLComm* source,
   264→    std::vector<int>& ranks_to_exclude,
   265→    ncclConfig_t* config,
   266→    int shrinkFlags) {
   267→  // Preconditions are validated in ProcessGroupNCCL::shrink
   268→
   269→  LOG(INFO) << "Rank " << source->rank_ << ": shrinking comm " << source->repr()
   270→            << " excluding " << ranks_to_exclude.size() << " ranks";
   271→
   272→  at::cuda::OptionalCUDAGuard gpuGuard(source->deviceIndex_);
   273→  auto comm = std::make_shared<NCCLComm>();
   274→
   275→  // This call will block until the source communicator is initialized
   276→  auto sourceComm = source->getNcclComm();
   277→
   278→  C10D_NCCL_CHECK_NONBLOCKING(
   279→      ncclCommShrink(
   280→          sourceComm,
   281→          ranks_to_exclude.data(),
   282→          ranks_to_exclude.size(),
   283→          reinterpret_cast<ncclComm_t*>(&(comm->ncclComm_)),
   284→          config,
   285→          shrinkFlags),
   286→      source->getNcclCommFailureReason());
   287→
   288→  // Wait for the child communicator to be ready
   289→  source->waitReady(true);
   290→  comm->initialized_ = true;
   291→
   292→  // NCCL automatically assigns rank during shrink - query it efficiently
   293→  int assigned_rank;
   294→  try {
   295→    C10D_NCCL_CHECK(
   296→        ncclCommUserRank(comm->ncclComm_, &assigned_rank), std::nullopt);
   297→    comm->rank_ = assigned_rank;
   298→  } catch (const std::exception& e) {
   299→    // Fallback: if ncclCommUserRank fails, we can't determine the rank
   300→    LOG(ERROR) << "Failed to query NCCL-assigned rank: " << e.what();
   301→    throw;
   302→  }
   303→
   304→  // Child comm should be on the same device as parent comm
   305→  comm->deviceIndex_ = source->deviceIndex_;
   306→  if (config != nullptr) {
   307→    comm->nonBlocking_ = config->blocking == 0;
   308→  } else {
   309→    // Inherit parent behavior if no config provided
   310→    comm->nonBlocking_ = source->nonBlocking_;
   311→  }
   312→
   313→  LOG(INFO) << "Rank " << source->rank_ << ": created shrunken comm "
   314→            << comm->repr() << " with NCCL-assigned rank " << assigned_rank;
   315→
   316→  return comm;
   317→}
   318→#endif
