   655→// Default value: 30 minutes
   656→int nccl_nonblocking_timeout() {
   657→  static int timeout = -2; // -2 means not initialized
   658→  if (timeout == -2) {
   659→    const auto val = c10::utils::get_env("TORCH_NCCL_NONBLOCKING_TIMEOUT");
   660→    if (val.has_value() && !val.value().empty()) {
   661→      timeout = stoi(val.value());
   662→    } else {
   663→      // Default value consistent with kBackendDefaultTimeout
   664→      timeout = 30 * 60;
   665→    }
   666→  }
   667→  return timeout;
   668→}
