  2722→std::exception_ptr ProcessGroupNCCL::checkForNCCLErrorsInternal(
  2723→    std::shared_ptr<NCCLComm>& ncclComm) {
  2724→  // Prioritize commFailureReason over checkForNcclError() result if
  2725→  // commFailureReason is set.
  2726→  auto commFailureReason = ncclComm->getNcclCommFailureReason();
  2727→  if (commFailureReason != std::nullopt) {
  2728→    return std::make_exception_ptr(C10_BUILD_ERROR(
  2729→        DistBackendError,
  2730→        c10::str(
  2731→            "NCCL communicator encountered error set by ProcessGroupNCCL: ",
  2732→            *commFailureReason)));
  2733→  }
  2734→  ncclResult_t ncclAsyncErr = ncclComm->checkForNcclError();
  2735→  // When nonblocking mode is enabled by TORCH_NCCL_USE_COMM_NONBLOCKING,
  2736→  // ncclInProgress could be returned when there are pending NCCL calls.
  2737→  // In this case, no exception should be thrown
  2738→#ifdef NCCL_HAS_COMM_NONBLOCKING
  2739→  // ncclInProgress is defined only if NCCL_HAS_COMM_NONBLOCKING is defined
  2740→  if (ncclAsyncErr != ncclSuccess && ncclAsyncErr != ncclInProgress) {
  2741→#else
  2742→  if (ncclAsyncErr != ncclSuccess) {
  2743→#endif // NCCL_HAS_COMM_NONBLOCKING
  2744→    return std::make_exception_ptr(C10_BUILD_ERROR(
  2745→        DistBackendError,
  2746→        "NCCL error: " + ncclGetErrorWithVersion(ncclAsyncErr) + "\n" +
  2747→            getNcclErrorDetailStr(ncclAsyncErr)));
  2748→  }
  2749→
  2750→  return nullptr;
  2751→}
