  2753→void ProcessGroupNCCL::broadcastUniqueNCCLID(
  2754→    ncclUniqueId* ncclID,
  2755→    bool isSingleP2POp,
  2756→    const std::string& p2pKey,
  2757→    int p2pRank) {
  2758→  // For collective operations:
  2759→  // For every NCCL communicator that we create we need to broadcast
  2760→  // a unique ID from rank 0 to all other ranks. This broadcast is
  2761→  // done by rank 0 setting a key in the store and all other ranks
  2762→  // retrieving the contents of that key. A single process group
  2763→  // may create multiple NCCL communicators, so we use a sequence
